type ApiResponse<T> = {
    data: T;
    status: number;
    timestamp: number;
};

type PartialResponse<T> = Partial<ApiResponse<T>>;
type ReadonlyResponse<T> = Readonly<ApiResponse<T>>;

interface Product {
    id: number;
    name: string;
    price: number;
}

async function fetchProduct(id: number): Promise<ApiResponse<Product> | null> {
    try {
        const response = await fetch(`/api/products/${id}`);
        if (!response.ok) return null;
        return await response.json() as ApiResponse<Product>;
    } catch (error) {
        console.error("Fetch failed:", error);
        return null;
    }
}

